Bash(node -e "
import\('./js/validation/RigidSurfaceAreaGenerator.js'\).then\(\({ RigidSurfaceAreaGenerator }\) => {
    let failures = 0;
    for \(let i = 0; i < 100; i++\) {
        const config = RigidSurfaceAreaGenerator.generateExact84Configuration\(\);
        const total = config.reduce\(\(s, m\) => s + m.surfaceArea, 0\);
        if \(total !== 84\) { failures++; }
    }
    console.log\('Failures out of 100:', failures\);
}\);
" 2>&1 | grep -E "^\(Failures|FAIL|Emergency\)")

